#!/usr/bin/env perl
use strict;
use warnings;

# Extract mature peptide sequences using SignalP 5 cleavage-site predictions.
# A sequence is retained when its ID occurs in type.txt (generated by filter.r).
# When both organism models predict a cleavage site, the smaller cleavage
# position is used to avoid over-trimming the mature sequence.
#
# Usage:
#   perl extract_type_seq.pl [type.txt] [protein.fasta] [output.fasta] \
#       [gram_positive_summary] [gram_negative_summary]

my $type_file = $ARGV[0] // 'type.txt';
my $protein_file = $ARGV[1] // 'protein.fasta';
my $output_file = $ARGV[2] // 'signal_cut.fasta';
my $gp_file = $ARGV[3] // 'SignalPredResult_summary.signalp5';
my $gn_file = $ARGV[4] // 'SignalPredResult2_summary.signalp5';

my %selected;
open my $TYPE, '<', $type_file or die "Cannot open $type_file: $!\n";
while (my $line = <$TYPE>) {
    chomp $line;
    $line =~ s/\r$//;
    next if $line =~ /^\s*$/;
    my ($id) = split /\t/, $line, 2;
    $selected{$id} = 1 if defined $id && $id ne '';
}
close $TYPE;

my %cuts;
for my $file ($gp_file, $gn_file) {
    open my $SP, '<', $file or die "Cannot open $file: $!\n";
    while (my $line = <$SP>) {
        next if $line =~ /^#/;
        chomp $line;
        $line =~ s/\r$//;
        my @fields = split /\t/, $line;
        my $id = $fields[0] // '';
        next unless exists $selected{$id};

        # SignalP 5 cleavage-site strings commonly contain "CS pos: 1-23".
        my @ranges = ($line =~ /(\d+)\s*-\s*(\d+)/g);
        next unless @ranges >= 2;
        my $cut_after = $ranges[1];
        next unless $cut_after =~ /^\d+$/;
        push @{ $cuts{$id} }, $cut_after;
    }
    close $SP;
}

my %sequences;
open my $FA, '<', $protein_file or die "Cannot open $protein_file: $!\n";
my ($current_id, $sequence) = ('', '');
while (my $line = <$FA>) {
    chomp $line;
    $line =~ s/\r$//;
    if ($line =~ /^>(\S+)/) {
        $sequences{$current_id} = $sequence if $current_id ne '';
        $current_id = $1;
        $sequence = '';
    } else {
        $line =~ s/\s+//g;
        $sequence .= $line;
    }
}
$sequences{$current_id} = $sequence if $current_id ne '';
close $FA;

open my $OUT, '>', $output_file or die "Cannot write $output_file: $!\n";
my $written = 0;
for my $id (sort keys %cuts) {
    next unless exists $sequences{$id};
    my $cut_after = (sort { $a <=> $b } @{ $cuts{$id} })[0];
    my $full = $sequences{$id};
    next if $cut_after >= length($full);
    # Perl uses zero-based offsets: position 23 means mature sequence starts
    # at residue 24, hence substr(..., 23).
    my $mature = substr($full, $cut_after);
    next if $mature eq '';
    print {$OUT} ">$id\n$mature\n";
    $written++;
}
close $OUT;

warn "Wrote $written mature peptide sequences to $output_file\n";
